#include <stdio.h>
#include <stdlib.h>
#include <string.h>
typedef struct Customer {
    int si, fi, pi;
} Customer;
int compare(const void *a, const void *b) {
    Customer *c1 = (Customer *)a;
    Customer *c2 = (Customer *)b;
    return c1->fi - c2->fi;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        Customer *customers = (Customer *)malloc(N * sizeof(Customer));
        for (int i = 0; i < N; i++) {
            scanf("%d %d %d", &customers[i].si, &customers[i].fi, &customers[i].pi);
        }
        qsort(customers, N, sizeof(Customer), compare);
        int *compartment = (int *)malloc(K * sizeof(int));
        memset(compartment, 0, K * sizeof(int));
        int max_customers = 0;
        for (int i = 0; i < N; i++) {
            if (customers[i].pi <= K && compartment[customers[i].pi - 1] == 0) {
                compartment[customers[i].pi - 1] = 1;
                max_customers++;
            }
        }
        printf("%d\n", max_customers);
        free(customers);
        free(compartment);
    }
    return 0;
}

