struct Customer {
    int si, fi, pi;
};
bool compare(const Customer &c1, const Customer &c2) {
    return c1.fi < c2.fi;
}
int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        int N, K;
        cin >> N >> K;
        Customer *customers = new Customer[N];
        for (int i = 0; i < N; i++) {
            cin >> customers[i].si >> customers[i].fi >> customers[i].pi;
        }
        sort(customers, customers + N, compare);
        int *compartment = new int[K];
        fill(compartment, compartment + K, 0);
        int max_customers = 0;
        for (int i = 0; i < N; i++) {
            if (customers[i].pi <= K && compartment[customers[i].pi - 1] == 0) {
                compartment[customers[i].pi - 1] = 1;
                max_customers++;
            }
        }
        cout << max_customers << endl;
        delete[] customers;
        delete[] compartment;
    }
    return 0;
}

