import java.util.Arrays;
import java.util.Scanner;
public class Main {
    static class Customer implements Comparable<Customer> {
        int si, fi, pi;
        public Customer(int si, int fi, int pi) {
            this.si = si;
            this.fi = fi;
            this.pi = pi;
        }
        @Override
        public int compareTo(Customer o) {
            return this.fi - o.fi;
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            Customer[] customers = new Customer[N];
            for (int i = 0; i < N; i++) {
                customers[i] = new Customer(sc.nextInt(), sc.nextInt(), sc.nextInt());
            }
            Arrays.sort(customers);
            int[] compartment = new int[K];
            int max_customers = 0;
            for (int i = 0; i < N; i++) {
                if (customers[i].pi <= K && compartment[customers[i].pi - 1] == 0) {
                    compartment[customers[i].pi - 1] = 1;
                    max_customers++;
                }
            }
            System.out.println(max_customers);
        }
    }
}

