const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, K] = readline().split(' ').map(Number);
    const customers = [];
    for (let j = 0; j < N; j++) {
        const [si, fi, pi] = readline().split(' ').map(Number);
        customers.push([si, fi, pi]);
    }
    customers.sort((a, b) => a[1] - b[1]);
    const compartment = new Array(K).fill(0);
    let max_customers = 0;
    for (let j = 0; j < N; j++) {
        if (customers[j][2] <= K && compartment[customers[j][2] - 1] === 0) {
            compartment[customers[j][2] - 1] = 1;
            max_customers++;
        }
    }
    console.log(max_customers);
}

